225	// blockParentDecomposed marks the parent as blocked-by-children: sets
226	// status=blocked, adds deps on children (so they must close first), and
227	// appends a kind:triage-decomposed event listing the child IDs.
228	func blockParentDecomposed(store TriageStore, parentID string, childIDs []string, rationale string, now func() time.Time) {
229		body, _ := json.Marshal(map[string]any{
230			"child_ids": childIDs,
231			"rationale": rationale,
232		})
233		_ = store.AppendEvent(parentID, bead.BeadEvent{
234			Kind:      "triage-decomposed",
235			Summary:   fmt.Sprintf("decomposed into %d children: %v", len(childIDs), childIDs),
236			Body:      string(body),
237			Actor:     "ddx",
238			Source:    "ddx triage gate",
239			CreatedAt: now().UTC(),
240		})
241		_ = store.Update(parentID, func(b *bead.Bead) {
242			b.Status = bead.StatusBlocked
243			if b.Extra == nil {
244				b.Extra = make(map[string]any)
245			}
246			b.Extra["triage_block_reason"] = "blocked-by-children"
247			b.Extra["triage_child_ids"] = childIDs
248			if !HasBeadLabel(b.Labels, "triage:decomposed") {
249				b.Labels = append(b.Labels, "triage:decomposed")
250			}
251			// Dependency edges ensure ReadyExecution excludes the parent until
252			// all children close (when/if the parent is later re-opened).
253			for _, childID := range childIDs {
254				b.AddDep(childID, "blocks")
255			}
256		})
257	}
